import { useEffect, useState } from "react";
import { Link, useNavigate } from "react-router-dom";

function Dashboard() {
  const [questions, setQuestions] = useState([]);
  const [notes, setNotes] = useState([]);
  const [search, setSearch] = useState("");

  const navigate = useNavigate();
  const user = JSON.parse(localStorage.getItem("user"));

  // ✅ Protect route
  useEffect(() => {
    if (!user) {
      navigate("/login");
    }
  }, [navigate, user]);

  // ✅ Fetch questions
  useEffect(() => {
    fetch("http://localhost:5000/api/questions")
      .then((res) => res.json())
      .then((data) => setQuestions(data));
  }, []);

  // ✅ Fetch all notes
  const fetchNotes = async () => {
    const res = await fetch("http://localhost:5000/api/notes");
    const data = await res.json();
    setNotes(data);
  };

  useEffect(() => {
    fetchNotes();
  }, []);

  // ✅ Logout
  const handleLogout = () => {
    localStorage.removeItem("user");
    navigate("/login");
  };

  // ✅ Search notes (ONLY matching results)
  const handleSearch = async () => {
    if (!search.trim()) {
      alert("Enter a topic to search");
      return;
    }

    try {
      const res = await fetch(
        `http://localhost:5000/api/notes/search?topic=${search}`
      );
      const data = await res.json();

      setNotes(data); // 🔥 Only matching notes shown

      if (data.length === 0) {
        alert("No notes found for this topic");
      }
    } catch (err) {
      console.error(err);
    }
  };

  // ✅ Reset notes
  const handleReset = () => {
    setSearch("");
    fetchNotes();
  };

  return (
    <div className="dashboard-full">

      {/* HEADER */}
      <div className="dashboard-header">
        <h2>Dashboard</h2>

        <div className="top-right">
          <button onClick={() => navigate("/")}>Home</button>
          <button onClick={handleLogout}>Logout</button>
        </div>
      </div>

      {/* QUESTIONS */}
      <h3>Questions</h3>

      {questions.length === 0 ? (
        <p>No questions yet</p>
      ) : (
        questions.map((q) => (
          <div key={q._id} className="dashboard-question">
            <h4>{q.title}</h4>
            <p>{q.description}</p>

            <Link to={`/answers/${q._id}`} className="dashboard-btn">
              View Answer
            </Link>
          </div>
        ))
      )}

      <Link to="/ask" className="dashboard-ask">
        Ask New Question
      </Link>

      {/* NOTES SECTION */}
      <h3 style={{ marginTop: "30px" }}>Notes</h3>

      {/* SEARCH BAR */}
      <div style={{ marginBottom: "10px" }}>
        <input
          placeholder="Search by topic (Java, DBMS...)"
          value={search}
          onChange={(e) => setSearch(e.target.value)}
        />

        <button onClick={handleSearch}>Search</button>
        <button onClick={handleReset}>Reset</button>
      </div>

      {/* NOTES LIST */}
      {notes.length === 0 ? (
        <p>No notes found</p>
      ) : (
        notes.map((n) => (
          <div key={n._id} className="dashboard-question">
            <h4>{n.title}</h4>
            <p><b>Topic:</b> {n.topic}</p>
            <p><b>Uploaded by:</b> {n.uploadedBy}</p>

            <a
              href={`http://localhost:5000/uploads/${n.file}`}
              target="_blank"
              rel="noreferrer"
              className="dashboard-btn"
            >
              View PDF
            </a>
          </div>
        ))
      )}

      {/* UPLOAD BUTTON (ONLY SENIOR) */}
      {user?.role === "Senior" && (
        <Link to="/upload" className="dashboard-ask">
          Upload Notes
        </Link>
      )}

    </div>
  );
}

export default Dashboard;
